import { useState, useEffect } from 'react';

export const useConversation = () => {
  const [messages, setMessages] = useState([]);
  const [isTyping, setIsTyping] = useState(false);
  const [userData, setUserData] = useState({});
  const [currentStep, setCurrentStep] = useState({ type: 'text' });

  const systemInstructions = `
    You are a NIMHANS Clinical Data Engine. 
    GOAL: Collect history efficiently. Use "choice" type whenever possible to minimize user typing.
    PROTOCOL ORDER: 1. Name, 2. Age, 3. Gender, 4. Chief Complaint, 5. History.

    RULES:
    - If a question has common answers (like Gender, Yes/No, or Symptom lists), use "type": "choice".
    - Respond ONLY in this JSON format:
    {
      "message": "Question text",
      "type": "text" | "choice" | "slider",
      "field": "db_field_name",
      "options": ["Option 1", "Option 2"] (Required if type is choice)
    }
  `;

  useEffect(() => {
    const init = async () => {
      setIsTyping(true);
      const res = await callOllama("Start by asking for the patient's name.");
      const parsed = JSON.parse(res);
      setMessages([{ sender: 'bot', text: parsed.message }]);
      setCurrentStep(parsed);
      setIsTyping(false);
    };
    init();
  }, []);

  const callOllama = async (prompt) => {
    const response = await fetch("http://localhost:11434/api/generate", {
      method: "POST",
      body: JSON.stringify({
        model: "mistral",
        prompt: `INSTRUCTIONS: ${systemInstructions}\n\nCONTEXT: ${prompt}`,
        stream: false,
        format: "json"
      }),
    });
    const data = await response.json();
    return data.response;
  };

  const handleUserAnswer = async (answer) => {
    setMessages(prev => [...prev, { sender: 'user', text: answer }]);
    setIsTyping(true);

    const updatedData = { ...userData, [currentStep.field]: answer };
    setUserData(updatedData);

    // Explicitly tell the LLM what we have and what is next in the NIMHANS protocol
    const contextPrompt = `
      Data collected: ${JSON.stringify(updatedData)}
      Last answer: "${answer}"
      Next step: Follow the NIMHANS sequence. If the next step is Gender or common symptoms, use "type": "choice".
    `;

    const nextJson = await callOllama(contextPrompt);
    const parsed = JSON.parse(nextJson);
    
    setMessages(prev => [...prev, { sender: 'bot', text: parsed.message }]);
    setCurrentStep(parsed);
    setIsTyping(false);
  };

  return { messages, isTyping, currentStep, handleUserAnswer, userData };
};
